import UIKit

class UniversalLinksViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        handleUniversalLink()
    }

    private func handleUniversalLink() {
        guard let url = userActivity?.webpageURL else { return }

        // BROKEN: Manual URL parsing fails on iOS 17+ with special characters
        // This causes EXC_BAD_ACCESS when session_id contains colon
        let components = url.absoluteString.split(separator: "?")
        if let queryString = components.last {
            let params = queryString.split(separator: "&")
            for param in params {
                let pair = param.split(separator: "=")
                if pair.first == "session_id" {
                    // Crash on iOS 17 - colon not properly escaped
                    let sessionId = String(pair.last ?? "")
                    processSession(sessionId)
                }
            }
        }
    }

    // FIXED: Use URLComponents for proper parsing
    private func handleUniversalLinkFixed() {
        guard let url = userActivity?.webpageURL,
              var components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return
        }

        let params = components.queryItems ?? []
        if let sessionId = params.first(where: { $0.name == "session_id" })?.value {
            processSession(sessionId)
        }
    }

    private func processSession(_ sessionId: String) {
        // Navigate to account view
    }
}

