import androidx.lifecycle.ViewModel
import androidx.camera.core.CameraSelector
import androidx.camera.lifecycle.ProcessCameraProvider
import android.content.Context
import android.Manifest

class CameraViewModel(private val context: Context) : ViewModel() {

    private val requestedPermissions = mutableListOf<String>()

    // PROBLEM: Requesting permission at runtime when already in AndroidManifest.xml
    fun requestCameraPermission(activity: androidx.appcompat.app.AppCompatActivity) {
        // This triggers BOTH system prompt AND our custom prompt on Android 13+
        androidx.core.app.ActivityCompat.requestPermissions(
            activity,
            arrayOf(Manifest.permission.CAMERA),
            CAMERA_PERMISSION_CODE
        )
    }

    // FIXED: Only request at runtime, remove from AndroidManifest.xml
    fun requestCameraPermissionFixed(activity: androidx.appcompat.app.AppCompatActivity) {
        if (androidx.core.content.ContextCompat.checkSelfPermission(
            context, Manifest.permission.CAMERA
        ) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
            androidx.core.app.ActivityCompat.requestPermissions(
                activity,
                arrayOf(Manifest.permission.CAMERA),
                CAMERA_PERMISSION_CODE
            )
        }
    }

    fun onPermissionResult(
        requestCode: Int,
        permissions: Array<String>,
        grantResults: IntArray
    ) {
        when (requestCode) {
            CAMERA_PERMISSION_CODE -> {
                if (grantResults.isNotEmpty() && 
                    grantResults[0] == android.content.pm.PackageManager.PERMISSION_GRANTED) {
                    // Open camera
                } else {
                    // Show explanation
                }
            }
        }
    }

    companion object {
        private const val CAMERA_PERMISSION_CODE = 100
    }
}

